namespace ProductsApi.Models;

public enum Category
{
    Electronics,
    Clothing,
    Food,
    Books
}

public class Product
{
    public Guid Id { get; set; }
    public required string Name { get; set; }
    public decimal Price { get; set; }
    public Category Category { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class CreateProductRequest
{
    public required string Name { get; set; }
    public decimal Price { get; set; }
    public Category Category { get; set; }
}

using ProductsApi.Models;

namespace ProductsApi.Services;

public interface IProductService
{
    IReadOnlyList<Product> GetAll();
    Product? GetById(Guid id);
    Product Create(CreateProductRequest request);
}

using System.Collections.Concurrent;
using ProductsApi.Models;

namespace ProductsApi.Services;

public class InMemoryProductService : IProductService
{
    private readonly ConcurrentDictionary<Guid, Product> _products = new();

    public IReadOnlyList<Product> GetAll() => _products.Values.ToList().AsReadOnly();

    public Product? GetById(Guid id) => _products.GetValueOrDefault(id);

    public Product Create(CreateProductRequest request)
    {
        var product = new Product
        {
            Id = Guid.NewGuid(),
            Name = request.Name,
            Price = request.Price,
            Category = request.Category,
            CreatedAt = DateTime.UtcNow
        };

        _products[product.Id] = product;
        return product;
    }
}

using Microsoft.AspNetCore.Http.HttpResults;
using ProductsApi.Models;
using ProductsApi.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<IProductService, InMemoryProductService>();
builder.Services.AddOpenApi();

var app = builder.Build();

app.MapOpenApi();

var products = app.MapGroup("/api/products")
    .WithTags("Products");

products.MapGet("/", (IProductService service) => service.GetAll())
    .WithName("GetAllProducts")
    .WithSummary("List all products")
    .WithDescription("Returns a list of all products in the catalog.");

products.MapGet("/{id:guid}", Results<Ok<Product>, NotFound> (Guid id, IProductService service) =>
    {
        var product = service.GetById(id);
        return product is not null ? TypedResults.Ok(product) : TypedResults.NotFound();
    })
    .WithName("GetProductById")
    .WithSummary("Get a product by ID")
    .WithDescription("Returns a single product matching the specified unique identifier, or 404 if not found.");

products.MapPost("/", Created<Product> (CreateProductRequest request, IProductService service) =>
    {
        var product = service.Create(request);
        return TypedResults.Created($"/api/products/{product.Id}", product);
    })
    .WithName("CreateProduct")
    .WithSummary("Create a new product")
    .WithDescription("Creates a new product in the catalog and returns the created resource with its generated ID and timestamp.");

app.Run();

